async function sendProviderSms(to, body, meta = {}) {
  const provider = MESSAGING_PROVIDER;
  if (!body) throw new Error('Message needs a message body.');
  if (!to) return { sent: false, status: 'Needs phone', provider: provider || 'not_configured', message: 'Add the customer phone number before sending.' };
  const settings = meta.messagingSettings || { enabled: WOA_MESSAGING_ENABLED };
  if (!settings.enabled) return { sent: false, status: 'Messaging off', provider: provider || 'not_configured', message: 'Messaging is turned off in WheelsonAuto settings or Render.' };
  if (!MESSAGING_FROM_NUMBER) return { sent: false, status: 'Ready to send', provider: provider || 'not_configured', message: 'Add the hosted SMS number in Render first.' };
  if (provider === 'twilio' && TWILIO_ACCOUNT_SID && TWILIO_AUTH_TOKEN) {
    const form = new URLSearchParams({ From: MESSAGING_FROM_NUMBER, To: cleanPhone(to), Body: body });
    const auth = Buffer.from(TWILIO_ACCOUNT_SID + ':' + TWILIO_AUTH_TOKEN).toString('base64');
    const response = await fetch('https://api.twilio.com/2010-04-01/Accounts/' + encodeURIComponent(TWILIO_ACCOUNT_SID) + '/Messages.json', {
      method: 'POST',
      headers: { Authorization: 'Basic ' + auth, 'Content-Type': 'application/x-www-form-urlencoded' },
      body: form
    });
    const jsonBody = await response.json().catch(() => ({}));
    if (!response.ok) throw new Error(jsonBody.message || 'Twilio message failed.');
    return { sent: true, status: jsonBody.status || 'Sent', provider: 'twilio', externalId: jsonBody.sid || '', response: jsonBody };
  }
  if (provider === 'telnyx' && TELNYX_API_KEY) {
    const telnyxPayload = {
      from: cleanPhone(MESSAGING_FROM_NUMBER),
      to: cleanPhone(to),
      text: body,
      auto_detect: true,
      encoding: 'auto',
      webhook_url: PUBLIC_BASE_URL + '/api/webhooks/messages?provider=telnyx',
      use_profile_webhooks: true
    };
    const profileId = String(meta.messagingProfileId || TELNYX_MESSAGING_PROFILE_ID || '').trim();
    if (profileId) telnyxPayload.messaging_profile_id = profileId;
    const response = await fetch('https://api.telnyx.com/v2/messages', {
      method: 'POST',
      headers: { Authorization: 'Bearer ' + TELNYX_API_KEY, 'Content-Type': 'application/json' },
      body: JSON.stringify(telnyxPayload)
    });
    const jsonBody = await response.json().catch(() => ({}));
    if (!response.ok) throw new Error((jsonBody.errors && jsonBody.errors[0] && jsonBody.errors[0].detail) || jsonBody.message || 'Telnyx message failed.');
    const telnyxData = jsonBody.data || {};
    const destination = Array.isArray(telnyxData.to) ? telnyxData.to[0] || {} : {};
    return { sent: true, status: destination.status || telnyxData.status || 'Queued', provider: 'telnyx', externalId: telnyxData.id || '', response: jsonBody };
  }
  return { sent: false, status: 'Ready to send', provider: provider || 'not_configured', message: 'Hosted SMS is not connected yet. Message saved in WheelsonAuto.' };
}
async function configureTwilioSmsWebhook(options = {}) {
  const accountSid = String(options.accountSid || TWILIO_ACCOUNT_SID || '').trim();
  const authToken = String(options.authToken || TWILIO_AUTH_TOKEN || '').trim();
  const phoneNumber = cleanPhone(options.phoneNumber || MESSAGING_FROM_NUMBER || '');
  const fetchImpl = options.fetchImpl || fetch;
  const webhookUrl = String(options.webhookUrl || (PUBLIC_BASE_URL + '/api/webhooks/messages?provider=twilio')).trim();
  if (!accountSid || !authToken || !phoneKey(phoneNumber)) {
    const error = new Error('Twilio account, auth token, and hosted SMS number must be saved in Render first.');
    error.statusCode = 409;
    throw error;
  }
  const auth = Buffer.from(accountSid + ':' + authToken).toString('base64');
  const base = 'https://api.twilio.com/2010-04-01/Accounts/' + encodeURIComponent(accountSid) + '/IncomingPhoneNumbers';
  const listResponse = await fetchImpl(base + '.json?PhoneNumber=' + encodeURIComponent(phoneNumber) + '&PageSize=50', {
    headers: { Authorization: 'Basic ' + auth }
  });
  const listBody = await listResponse.json().catch(() => ({}));
  if (!listResponse.ok) throw new Error(listBody.message || 'Twilio could not list the hosted SMS number.');
  const numbers = Array.isArray(listBody.incoming_phone_numbers) ? listBody.incoming_phone_numbers : [];
  const number = numbers.find(item => phoneKey(item && item.phone_number) === phoneKey(phoneNumber));
  if (!number || !number.sid) {
    const error = new Error('Twilio did not return the hosted SMS number for this account.');
    error.statusCode = 404;
    throw error;
  }
  const form = new URLSearchParams({ SmsUrl: webhookUrl, SmsMethod: 'POST' });
  const updateResponse = await fetchImpl(base + '/' + encodeURIComponent(number.sid) + '.json', {
    method: 'POST',
    headers: { Authorization: 'Basic ' + auth, 'Content-Type': 'application/x-www-form-urlencoded' },
    body: form
  });
  const updateBody = await updateResponse.json().catch(() => ({}));
  if (!updateResponse.ok) throw new Error(updateBody.message || 'Twilio could not connect inbound SMS to WheelsonAuto.');
  return {
    connected: true,
    provider: 'twilio',
    phoneNumber: maskPhone(updateBody.phone_number || number.phone_number || phoneNumber),
    webhookUrl: updateBody.sms_url || webhookUrl,
    smsMethod: updateBody.sms_method || 'POST'
  };
}
async function autoConfigureTwilioSmsWebhook() {
  if (MESSAGING_PROVIDER !== 'twilio' || !TWILIO_ACCOUNT_SID || !TWILIO_AUTH_TOKEN || !MESSAGING_FROM_NUMBER) {
    return { connected: false, skipped: true, status: 'Twilio is not fully configured in Render.' };
  }
  await writeDataQueue.catch(() => {});
  const data = await readData();
  data.integrations = data.integrations || {};
  data.integrations.messaging = data.integrations.messaging || {};
  const systemUser = { name: 'WheelsonAuto system', role: 'Owner', organizationId: MAIN_ORG_ID, companyName: 'WheelsonAuto' };
  try {
    const result = await configureTwilioSmsWebhook();
    data.integrations.messaging = { ...data.integrations.messaging, ...publicMessagingStatus(data) };
    Object.assign(data.integrations.messaging, {
      smsWebhookConnected: true,
      smsWebhookStatus: 'Inbound SMS connected',
      smsWebhookConfiguredAt: new Date().toISOString(),
      smsWebhookLastAttemptAt: new Date().toISOString(),
      smsWebhookLastError: '',
      lastError: ''
    });
    appendAuditLog(data, systemUser, 'Twilio inbox connected automatically', [result.phoneNumber || 'Hosted SMS number', result.webhookUrl, result.smsMethod]);
    await protectConcurrentLocalWrites(data);
    await writeData(data);
    return result;
  } catch (err) {
    const error = String(err && err.message || err);
    data.integrations.messaging = { ...data.integrations.messaging, ...publicMessagingStatus(data) };
    Object.assign(data.integrations.messaging, {
      smsWebhookConnected: false,
      smsWebhookStatus: data.integrations.messaging.smsPollingConnected ? 'Inbound SMS connected by secure sync' : 'Inbound SMS needs attention',
      smsWebhookLastAttemptAt: new Date().toISOString(),
      smsWebhookLastError: error,
      lastError: data.integrations.messaging.smsPollingConnected ? '' : error
    });
    appendAuditLog(data, systemUser, 'Automatic Twilio inbox connection failed', [error]);
    await protectConcurrentLocalWrites(data);
    await writeData(data);
    await recordOperationalFailure('twilio-inbound-setup', err, {
      route: 'Twilio inbound SMS webhook setup',
      source: 'automatic'
    });
    throw err;
  }
}
async function telnyxApiRequest(fetchImpl, apiKey, pathname, options = {}) {
  const response = await fetchImpl('https://api.telnyx.com/v2' + pathname, {
    ...options,
    headers: {
      Authorization: 'Bearer ' + apiKey,
      'Content-Type': 'application/json',
      ...(options.headers || {})
    }
  });
  const body = await response.json().catch(() => ({}));
  if (!response.ok) {
    const detail = body.errors && body.errors[0] && (body.errors[0].detail || body.errors[0].title);
    const error = new Error(detail || body.message || 'Telnyx setup request failed.');
    error.statusCode = response.status || 502;
    error.response = body;
    throw error;
  }
  return body;
}
async function configureTelnyxMessagingProfile(options = {}) {
  const apiKey = String(options.apiKey || TELNYX_API_KEY || '').trim();
  const phoneNumber = cleanPhone(options.phoneNumber || MESSAGING_FROM_NUMBER || '');
  const publicKey = String(options.publicKey || TELNYX_PUBLIC_KEY || '').trim();
  const fetchImpl = options.fetchImpl || fetch;
  const webhookUrl = String(options.webhookUrl || (PUBLIC_BASE_URL + '/api/webhooks/messages?provider=telnyx')).trim();
  let profileId = String(options.profileId || TELNYX_MESSAGING_PROFILE_ID || '').trim();
  if (!apiKey || !phoneKey(phoneNumber)) {
    const error = new Error('Telnyx API key and Telnyx SMS number must be saved in Render first.');
    error.statusCode = 409;
    throw error;
  }
  if (!publicKey || !telnyxPublicKeyObject(publicKey)) {
    const error = new Error('Add the Telnyx public key in Render so inbound messages can be verified securely.');
    error.statusCode = 409;
    throw error;
  }
  if (!profileId) {
    const profilesBody = await telnyxApiRequest(fetchImpl, apiKey, '/messaging_profiles?page[size]=250');
    const profiles = Array.isArray(profilesBody.data) ? profilesBody.data : [];
    const existing = profiles.find(item => String(item && item.name || '').toLowerCase() === TELNYX_MESSAGING_PROFILE_NAME.toLowerCase());
    profileId = String(existing && existing.id || '');
  }
  const profileSettings = {
    name: TELNYX_MESSAGING_PROFILE_NAME,
    webhook_url: webhookUrl,
    webhook_api_version: '2',
    smart_encoding: true,
    whitelisted_destinations: ['US']
  };
  if (!profileId) {
    const created = await telnyxApiRequest(fetchImpl, apiKey, '/messaging_profiles', { method: 'POST', body: JSON.stringify(profileSettings) });
    profileId = String(created.data && created.data.id || '');
  } else {
    await telnyxApiRequest(fetchImpl, apiKey, '/messaging_profiles/' + encodeURIComponent(profileId), { method: 'PATCH', body: JSON.stringify(profileSettings) });
  }
  if (!profileId) throw new Error('Telnyx did not return a messaging profile ID.');
  const numberBody = await telnyxApiRequest(fetchImpl, apiKey, '/phone_numbers?filter[phone_number]=' + encodeURIComponent(phoneNumber) + '&page[size]=50');
  const numbers = Array.isArray(numberBody.data) ? numberBody.data : [];
  const number = numbers.find(item => phoneKey(item && item.phone_number) === phoneKey(phoneNumber));
  if (!number || !number.id) {
    const error = new Error('Telnyx did not return this SMS number. Buy a temporary Telnyx test number before connecting the inbox.');
    error.statusCode = 404;
    throw error;
  }
  let assigned = String(number.messaging_profile_id || '') === profileId;
  if (!assigned) {
    try {
      await telnyxApiRequest(fetchImpl, apiKey, '/messaging_profiles/' + encodeURIComponent(profileId) + '/phone_numbers', {
        method: 'POST',
        body: JSON.stringify({ phone_number_id: number.id })
      });
      assigned = true;
    } catch (err) {
      const message = String(err && err.message || '').toLowerCase();
      if (!/already|assigned|associated/.test(message)) throw err;
      assigned = true;
    }
  }
  return {
    connected: true,
    provider: 'telnyx',
    phoneNumber: maskPhone(number.phone_number || phoneNumber),
    phoneNumberId: number.id,
    messagingProfileId: profileId,
    webhookUrl,
    smsMethod: 'POST',
    signedWebhooks: true,
    assigned
  };
}
async function checkTelnyx10dlcReadiness(options = {}) {
  const apiKey = String(options.apiKey || TELNYX_API_KEY || '').trim();
  const phoneNumber = cleanPhone(options.phoneNumber || MESSAGING_FROM_NUMBER || '');
  const fetchImpl = options.fetchImpl || fetch;
  if (!apiKey || !phoneKey(phoneNumber)) {
    const error = new Error('Telnyx API key and SMS number must be saved in Render first.');
    error.statusCode = 409;
    throw error;
  }
  let assignment = {};
  try {
    const assignmentBody = await telnyxApiRequest(fetchImpl, apiKey, '/10dlc/phone_number_campaigns/' + encodeURIComponent(phoneNumber));
    assignment = assignmentBody.data || assignmentBody || {};
  } catch (err) {
    if (Number(err && err.statusCode) !== 404) throw err;
  }
  let campaignId = String(assignment.campaignId || assignment.campaign_id || '').trim();
  const assignmentStatus = String(assignment.status || assignment.assignmentStatus || assignment.assignment_status || '').trim();
  let campaign = {};
  let campaignStatus = '';
  let brandStatus = '';
  let historicalCampaignStatus = '';
  let historicalFailureReason = '';
  let rejectedCampaignCount = 0;
  const campaignState = row => String(row && (row.campaignStatus || row.campaign_status || row.status || row.submissionStatus || row.submission_status) || '').trim().toUpperCase();
  const campaignFailure = row => {
    const raw = row && (row.failureReasons || row.failure_reasons || row.failureReason || row.failure_reason || row.reasons || row.reason);
    if (!raw) return '';
    if (typeof raw === 'string') return raw.trim().slice(0, 800);
    const values = Array.isArray(raw) ? raw : Object.values(raw);
    return values.map(item => {
      if (typeof item === 'string') return item.trim();
      return String(item && (item.detail || item.message || item.reason || item.description) || '').trim();
    }).filter(Boolean).join('; ').slice(0, 800);
  };
  const activeCampaignState = value => ['ACTIVE', 'APPROVED', 'MNO_PROVISIONED'].includes(String(value || '').trim().toUpperCase());
  const pendingCampaignState = value => ['CREATED', 'PENDING', 'TCR_PENDING', 'TCR_ACCEPTED', 'TELNYX_ACCEPTED', 'MNO_PENDING', 'MNO_ACCEPTED'].includes(String(value || '').trim().toUpperCase());
  const rejectedCampaignState = value => /FAILED|REJECTED|SUSPENDED|EXPIRED/.test(String(value || '').trim().toUpperCase());
  if (campaignId) {
    let campaignBody;
    try {
      campaignBody = await telnyxApiRequest(fetchImpl, apiKey, '/10dlc/campaignBuilder/' + encodeURIComponent(campaignId));
    } catch (err) {
      if (Number(err && err.statusCode) !== 404) throw err;
      campaignBody = await telnyxApiRequest(fetchImpl, apiKey, '/10dlc/campaign/' + encodeURIComponent(campaignId));
    }
    campaign = campaignBody.data || campaignBody || {};
    campaignStatus = campaignState(campaign);
  }
  const numberAssigned = !!campaignId && (!assignmentStatus || /^assigned$/i.test(assignmentStatus));
  if (!campaignId) {
    let campaigns = [];
    try {
      const campaignsBody = await telnyxApiRequest(fetchImpl, apiKey, '/10dlc/campaignBuilder?page[size]=50');
      campaigns = Array.isArray(campaignsBody.data) ? campaignsBody.data : Array.isArray(campaignsBody.records) ? campaignsBody.records : [];
    } catch (err) {
      if (Number(err && err.statusCode) !== 404) throw err;
    }
    try {
      const brandsBody = await telnyxApiRequest(fetchImpl, apiKey, '/10dlc/brand?page=1&recordsPerPage=500');
      const brands = Array.isArray(brandsBody.records) ? brandsBody.records : Array.isArray(brandsBody.data) ? brandsBody.data : [];
      const firstBrand = brands[0] || {};
      brandStatus = String(firstBrand.identityStatus || firstBrand.identity_status || firstBrand.status || '').trim().toUpperCase();
      for (const brand of brands) {
        const brandId = String(brand.brandId || brand.brand_id || brand.id || '').trim();
        if (!brandId) continue;
        const listed = await telnyxApiRequest(fetchImpl, apiKey, '/10dlc/campaign?brandId=' + encodeURIComponent(brandId) + '&page=1&recordsPerPage=500');
        const rows = Array.isArray(listed.records) ? listed.records : Array.isArray(listed.data) ? listed.data : [];
        campaigns.push(...rows);
      }
    } catch (err) {
      if (!campaigns.length || Number(err && err.statusCode) !== 404) throw err;
    }
    const uniqueCampaigns = Array.from(new Map(campaigns.map(row => [String(row.campaignId || row.campaign_id || row.id || JSON.stringify(row)), row])).values());
    const rejectedCampaigns = uniqueCampaigns.filter(row => rejectedCampaignState(campaignState(row)));
    const historicalCampaign = rejectedCampaigns[0] || {};
    rejectedCampaignCount = rejectedCampaigns.length;
    historicalCampaignStatus = campaignState(historicalCampaign);
    historicalFailureReason = campaignFailure(historicalCampaign);
    campaign = uniqueCampaigns.find(row => activeCampaignState(campaignState(row))) ||
      uniqueCampaigns.find(row => pendingCampaignState(campaignState(row))) ||
      uniqueCampaigns.find(row => !rejectedCampaignState(campaignState(row))) || {};
    campaignId = String(campaign.campaignId || campaign.campaign_id || campaign.id || '').trim();
    campaignStatus = campaignState(campaign);
  }
  const brandVerified = ['VERIFIED', 'VETTED_VERIFIED'].includes(brandStatus);
  const campaignActive = activeCampaignState(campaignStatus);
  const failureReason = campaignFailure(campaign) || historicalFailureReason;
  let registrationStage = 'brand_registration';
  let nextAction = 'Register and verify the WheelsonAuto business identity with Telnyx.';
  let summary = 'No Telnyx 10DLC brand was found yet.';
  if (numberAssigned && campaignActive) {
    registrationStage = 'delivery_test';
    nextAction = 'Run one outbound delivery test and confirm the inbound reply reaches the same customer thread.';
    summary = 'Telnyx 10DLC campaign is active and the SMS number is assigned. Run one outbound delivery test.';
  } else if (campaignActive && campaignId) {
    registrationStage = 'number_assignment';
    nextAction = 'Attach the WheelsonAuto SMS number to the approved campaign.';
    summary = 'An active Telnyx 10DLC campaign was found, but the SMS number is not attached to it.';
  } else if (brandStatus && !brandVerified) {
    registrationStage = 'brand_verification';
    nextAction = 'Wait for Telnyx to verify the corrected IRS legal name and CP-575 document before creating another campaign.';
    summary = 'Telnyx brand is ' + brandStatus + ' and awaiting identity verification.' + (historicalCampaignStatus ? ' The previous ' + historicalCampaignStatus + ' campaign is retained as history only.' : '');
  } else if (campaignId) {
    registrationStage = 'campaign_review';
    nextAction = 'Wait for Telnyx and carrier review to finish before assigning the number.';
    summary = 'Telnyx campaign is currently ' + (campaignStatus || 'under review') + '; the SMS number cannot be attached until approval is complete.' + (failureReason ? ' Reason: ' + failureReason : '');
  } else if (brandVerified) {
    registrationStage = 'campaign_creation';
    nextAction = 'Create a corrected customer-care campaign for the verified brand, then wait for carrier approval.';
    summary = 'Telnyx brand is verified. Create the corrected campaign next.' + (historicalCampaignStatus ? ' The previous ' + historicalCampaignStatus + ' campaign remains history only.' : '');
  } else if (brandStatus) {
    registrationStage = 'brand_verification';
    nextAction = 'Complete Telnyx brand verification before creating a campaign.';
    summary = 'Telnyx brand is currently ' + brandStatus + '.';
  }
  return {
    checkedAt: new Date().toISOString(),
    phoneNumber: maskPhone(phoneNumber),
    numberAssigned,
    assignmentStatus: assignmentStatus || (numberAssigned ? 'Assigned' : 'Not assigned'),
    campaignId,
    campaignStatus: campaignStatus || 'Not found',
    brandStatus: brandStatus || '',
    brandVerified,
    historicalCampaignStatus,
    historicalFailureReason,
    rejectedCampaignCount,
    failureReason,
    campaignActive,
    readyForDeliveryTest: numberAssigned && campaignActive,
    registrationStage,
    nextAction,
    summary
  };
}
function publicTelnyx10dlcReadiness(readiness = {}) {
  return {
    checkedAt: readiness.checkedAt || '',
    phoneNumber: readiness.phoneNumber || '',
    numberAssigned: !!readiness.numberAssigned,
    assignmentStatus: readiness.assignmentStatus || '',
    campaignId: readiness.campaignId ? 'stored securely' : '',
    campaignStatus: readiness.campaignStatus || '',
    brandStatus: readiness.brandStatus || '',
    brandVerified: !!readiness.brandVerified,
    historicalCampaignStatus: readiness.historicalCampaignStatus || '',
    historicalFailureReason: readiness.historicalFailureReason || '',
    rejectedCampaignCount: Number(readiness.rejectedCampaignCount || 0),
    failureReason: readiness.failureReason || '',
    campaignActive: !!readiness.campaignActive,
    readyForDeliveryTest: !!readiness.readyForDeliveryTest,
    registrationStage: readiness.registrationStage || '',
    nextAction: readiness.nextAction || '',
    assignmentRequestedAt: readiness.assignmentRequestedAt || '',
    summary: readiness.summary || ''
  };
}
async function assignTelnyx10dlcCampaign(options = {}) {
  const apiKey = String(options.apiKey || TELNYX_API_KEY || '').trim();
  const phoneNumber = cleanPhone(options.phoneNumber || MESSAGING_FROM_NUMBER || '');
  const fetchImpl = options.fetchImpl || fetch;
  const readiness = options.readiness || await checkTelnyx10dlcReadiness({ apiKey, phoneNumber, fetchImpl });
  const campaignId = String(options.campaignId || readiness.campaignId || '').trim();
  if (!apiKey || !phoneKey(phoneNumber) || !campaignId || !readiness.campaignActive) {
    const error = new Error('No approved active Telnyx campaign is ready to receive this SMS number.');
    error.statusCode = 409;
    throw error;
  }
  if (readiness.numberAssigned) return { ...readiness, alreadyAssigned: true };
  await telnyxApiRequest(fetchImpl, apiKey, '/10dlc/phone_number_campaigns/' + encodeURIComponent(phoneNumber), {
    method: 'PUT',
    body: JSON.stringify({ phoneNumber, campaignId })
  });
  return {
    ...readiness,
    assignmentRequestedAt: new Date().toISOString(),
    assignmentStatus: 'Assignment submitted',
    summary: 'Telnyx accepted the number-to-campaign assignment. Recheck readiness after carrier provisioning.'
  };
}
async function autoConfigureTelnyxMessagingProfile() {
  if (MESSAGING_PROVIDER !== 'telnyx' || !TELNYX_API_KEY || !TELNYX_PUBLIC_KEY || !MESSAGING_FROM_NUMBER) {
    return { connected: false, skipped: true, status: 'Telnyx is not fully configured in Render.' };
  }
  await writeDataQueue.catch(() => {});
  const data = await readData();
  data.integrations = data.integrations || {};
  data.integrations.messaging = data.integrations.messaging || {};
  const saved = data.integrations.messaging;
  const systemUser = { name: 'WheelsonAuto system', role: 'Owner', organizationId: MAIN_ORG_ID, companyName: 'WheelsonAuto' };
  try {
    const result = await configureTelnyxMessagingProfile({ profileId: saved.telnyxMessagingProfileId || TELNYX_MESSAGING_PROFILE_ID });
    data.integrations.messaging = { ...saved, ...publicMessagingStatus(data) };
    Object.assign(data.integrations.messaging, {
      telnyxMessagingProfileId: result.messagingProfileId,
      smsWebhookConnected: true,
      smsPollingConnected: false,
      smsWebhookStatus: 'Telnyx inbound SMS connected',
      smsWebhookConfiguredAt: new Date().toISOString(),
      smsWebhookLastAttemptAt: new Date().toISOString(),
      smsWebhookLastError: '',
      lastError: ''
    });
    appendAuditLog(data, systemUser, 'Telnyx inbox connected automatically', [result.phoneNumber, result.webhookUrl, 'Signed webhooks']);
    await protectConcurrentLocalWrites(data);
    await writeData(data);
    return result;
  } catch (err) {
    const error = String(err && err.message || err);
    data.integrations.messaging = { ...saved, ...publicMessagingStatus(data), smsWebhookConnected: false, smsWebhookStatus: 'Telnyx inbound SMS needs attention', smsWebhookLastAttemptAt: new Date().toISOString(), smsWebhookLastError: error, lastError: error };
    appendAuditLog(data, systemUser, 'Automatic Telnyx inbox connection failed', [error]);
    await protectConcurrentLocalWrites(data);
    await writeData(data);
    await recordOperationalFailure('telnyx-inbound-setup', err, {
      route: 'Telnyx inbound SMS profile setup',
      source: 'automatic'
    });
    throw err;
  }
}
async function listTwilioInboundMessages(options = {}) {
  const accountSid = String(options.accountSid || TWILIO_ACCOUNT_SID || '').trim();
  const authToken = String(options.authToken || TWILIO_AUTH_TOKEN || '').trim();
  const phoneNumber = cleanPhone(options.phoneNumber || MESSAGING_FROM_NUMBER || '');
  const fetchImpl = options.fetchImpl || fetch;
  if (!accountSid || !authToken || !phoneKey(phoneNumber)) {
    const error = new Error('Twilio account, auth token, and hosted SMS number must be saved in Render first.');
    error.statusCode = 409;
    throw error;
  }
  const auth = Buffer.from(accountSid + ':' + authToken).toString('base64');
  const params = new URLSearchParams({ To: phoneNumber, PageSize: String(Math.min(100, Math.max(1, Number(options.pageSize || 50)))) });
  const response = await fetchImpl('https://api.twilio.com/2010-04-01/Accounts/' + encodeURIComponent(accountSid) + '/Messages.json?' + params, {
    headers: { Authorization: 'Basic ' + auth }
  });
  const body = await response.json().catch(() => ({}));
  if (!response.ok) throw new Error(body.message || 'Twilio could not read inbound messages.');
  return (Array.isArray(body.messages) ? body.messages : []).filter(message => {
    return String(message && message.direction || '').toLowerCase() === 'inbound'
      && phoneKey(message && message.to) === phoneKey(phoneNumber)
      && !!(message && message.sid);
  });
}
function twilioSignatureForPayload(webhookUrl, payload, authToken = TWILIO_AUTH_TOKEN) {
  const signed = Object.keys(payload || {}).sort().reduce((value, key) => value + key + String(payload[key] == null ? '' : payload[key]), webhookUrl);
  return crypto.createHmac('sha1', authToken).update(signed).digest('base64');
}
async function deliverPolledTwilioMessage(message, options = {}) {
  const fetchImpl = options.fetchImpl || fetch;
  const webhookUrl = String(options.webhookUrl || (PUBLIC_BASE_URL + '/api/webhooks/messages?provider=twilio')).trim();
  const payload = {
    From: cleanPhone(message.from || ''),
    To: cleanPhone(message.to || MESSAGING_FROM_NUMBER || ''),
    Body: String(message.body || ''),
    MessageSid: String(message.sid || ''),
    SmsSid: String(message.sid || ''),
    NumMedia: String(message.num_media || '0')
  };
  const response = await fetchImpl(webhookUrl, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
      'X-Twilio-Signature': twilioSignatureForPayload(webhookUrl, payload, options.authToken || TWILIO_AUTH_TOKEN)
    },
    body: new URLSearchParams(payload)
  });
  const body = await response.json().catch(() => ({}));
  if (!response.ok) throw new Error(body.error || 'WheelsonAuto could not accept the synced Twilio message.');
  return body;
}
async function persistTwilioPollingStatus(result, error = '') {
  const data = await readData();
  data.integrations = data.integrations || {};
  const current = data.integrations.messaging || {};
  data.integrations.messaging = { ...current, ...publicMessagingStatus(data) };
  Object.assign(data.integrations.messaging, {
    smsPollingConnected: !error,
    smsInboundConnected: !error || current.smsWebhookConnected === true,
    smsInboundMode: current.smsWebhookConnected === true ? 'webhook' : (!error ? 'secure sync' : ''),
    smsPollingStatus: error ? 'Secure sync needs attention' : 'Five-second secure sync active',
    smsPollingLastCheckedAt: new Date().toISOString(),
    smsPollingLastDeliveredAt: result && result.delivered ? new Date().toISOString() : (current.smsPollingLastDeliveredAt || ''),
    smsPollingLastCount: Number(result && result.delivered || 0),
    smsWebhookStatus: current.smsWebhookConnected === true ? 'Inbound SMS connected' : (!error ? 'Inbound SMS connected by secure sync' : 'Inbound SMS needs attention'),
    lastError: current.smsWebhookConnected === true ? '' : error
  });
  await protectConcurrentLocalWrites(data);
  await writeData(data);
  twilioInboundPollStatus.lastPersistedAt = Date.now();
}
async function syncTwilioInboundMessages(options = {}) {
  if (twilioInboundPollStatus.inFlight) return { skipped: true, reason: 'Twilio inbound sync already running.' };
  const configured = String(options.provider || MESSAGING_PROVIDER) === 'twilio'
    && !!(options.accountSid || TWILIO_ACCOUNT_SID)
    && !!(options.authToken || TWILIO_AUTH_TOKEN)
    && !!phoneKey(options.phoneNumber || MESSAGING_FROM_NUMBER);
  if (!configured) return { skipped: true, reason: 'Twilio is not fully configured.' };
  twilioInboundPollStatus.inFlight = true;
  try {
    const messages = await listTwilioInboundMessages(options);
    const data = options.data || await readData();
    const existing = new Set((data.messages || []).map(item => String(item && item.externalId || '')).filter(Boolean));
    const pending = messages
      .filter(message => !existing.has(String(message.sid || '')))
      .sort((a, b) => new Date(a.date_sent || a.date_created || 0) - new Date(b.date_sent || b.date_created || 0))
      .slice(0, 25);
    const deliver = options.deliver || (message => deliverPolledTwilioMessage(message, options));
    let delivered = 0;
    for (const message of pending) {
      const response = await deliver(message);
      if (!response || response.received !== false || response.duplicate) delivered += response && response.duplicate ? 0 : 1;
    }
    const result = { checked: messages.length, pending: pending.length, delivered };
    twilioInboundPollStatus.lastCheckedAt = new Date().toISOString();
    twilioInboundPollStatus.lastDeliveredAt = delivered ? twilioInboundPollStatus.lastCheckedAt : twilioInboundPollStatus.lastDeliveredAt;
    twilioInboundPollStatus.lastError = '';
    twilioInboundPollStatus.lastResult = result;
    const shouldPersist = options.persist !== false && (!(((data.integrations || {}).messaging || {}).smsPollingConnected) || delivered > 0 || Date.now() - twilioInboundPollStatus.lastPersistedAt >= 5 * 60 * 1000);
    if (shouldPersist) await persistTwilioPollingStatus(result);
    return result;
  } catch (err) {
    const error = String(err && err.message || err);
    twilioInboundPollStatus.lastCheckedAt = new Date().toISOString();
    twilioInboundPollStatus.lastError = error;
    twilioInboundPollStatus.lastResult = null;
    if (options.persist !== false && Date.now() - twilioInboundPollStatus.lastPersistedAt >= 60 * 1000) await persistTwilioPollingStatus(null, error);
    await recordOperationalFailure('twilio-inbound-sync', err, {
      route: 'Twilio inbound SMS secure sync',
      source: String(options.source || 'automatic')
    });
    throw err;
  } finally {
    twilioInboundPollStatus.inFlight = false;
  }
}
async function sendOwnerSmsMirror(data, payload = {}, settings = messageSettings(data)) {
  data.messages = Array.isArray(data.messages) ? data.messages : [];
  const customerPhone = cleanPhone(payload.phone || payload.from || payload.to || '');
  if (!MESSAGING_OWNER_NOTIFY_NUMBER || !phoneKey(customerPhone) || phoneKey(customerPhone) === phoneKey(MESSAGING_OWNER_NOTIFY_NUMBER)) {
    return { sent: false, skipped: true, status: 'Owner mirror not configured' };
  }
  const thread = rememberSmsBridgeThread(data, { ...payload, phone: customerPhone });
  if (!thread) return { sent: false, skipped: true, status: 'Customer phone missing' };
  const scam = payload.scam || smsScamAssessment(payload.body || '');
  const body = ownerSmsMirrorBody({ ...payload, phone: customerPhone }, thread, scam);
  let result;
  let error = '';
  try {
    result = await sendProviderSms(MESSAGING_OWNER_NOTIFY_NUMBER, body, { customer: 'WheelsonAuto owner', ownerMirror: true, messagingSettings: settings });
  } catch (err) {
    error = String(err && err.message || err);
    result = { sent: false, status: 'Mirror failed', provider: MESSAGING_PROVIDER || 'not_configured', message: error };
  }
  const record = {
    id: 'msg-mirror-' + Date.now() + '-' + crypto.randomBytes(2).toString('hex'),
    externalId: result.externalId || '',
    date: new Date().toLocaleString('en-US'),
    createdAt: new Date().toISOString(),
    customer: payload.customer || thread.customer || customerPhone,
    organizationId: payload.organizationId || thread.organizationId || MAIN_ORG_ID,
    phone: customerPhone,
    customerPhone,
    ownerPhone: MESSAGING_OWNER_NOTIFY_NUMBER,
    to: MESSAGING_OWNER_NOTIFY_NUMBER,
    direction: 'Owner mirror',
    channel: 'SMS',
    template: scam.suspicious ? 'Potential scam warning' : 'Owner notification',
    subject: String(payload.direction || '').toLowerCase().startsWith('out') ? 'Outbound text mirrored to owner phone' : 'Customer text mirrored to owner phone',
    status: result.sent ? (result.status || 'Sent') : (result.status || 'Ready to send'),
    tone: scam.suspicious || error ? 'bad' : (result.sent ? 'good' : 'warn'),
    body,
    provider: result.provider || MESSAGING_PROVIDER || 'not_configured',
    source: 'WheelsonAuto phone mirror',
    bridgeCode: thread.code,
    scamReasons: scam.reasons || [],
    hiddenFromInbox: true,
    customerId: payload.customerId || thread.customerId || '',
    contractId: payload.contractId || thread.contractId || '',
    recurringPaymentId: payload.recurringPaymentId || thread.recurringPaymentId || '',
    vehicleId: payload.vehicleId || thread.vehicleId || '',
    vehicle: payload.vehicle || thread.vehicle || '',
    vin: payload.vin || thread.vin || '',
    licensePlate: payload.licensePlate || payload.plate || thread.licensePlate || '',
    tracker: payload.tracker || thread.tracker || '',
    error
  };
  data.messages.unshift(record);
  return { ...result, record, bridgeCode: thread.code, error };
}
