    aiEnabled: messageSettings(data).aiEnabled,
    aiConfigured: !!(OPENAI_API_KEY && WOA_AI_MODEL),
    provider,
    mode: plan.mode || provider,
    model: provider === 'openai' ? WOA_AI_MODEL : '',
