function vehicleIdentityGapRows(data = {}) {
  return (Array.isArray(data.vehicles) ? data.vehicles : []).filter(vehicle => {
    if (/removed/i.test(String(vehicle.status || ''))) return false;
    return !String(vehicle.vin || '').trim() || !String(vehicle.plate || vehicle.stock || vehicle.licensePlate || '').trim() || !trackerName(vehicle);
  }).map(vehicle => {
    const missing = [];
    if (!String(vehicle.vin || '').trim()) missing.push('VIN');
    if (!String(vehicle.plate || vehicle.stock || vehicle.licensePlate || '').trim()) missing.push('tag/plate');
    if (!trackerName(vehicle)) missing.push('tracker');
    return {
      id: vehicle.id || '',
      vehicle: vehicleNameFromParts(vehicle),
      customer: vehicle.currentCustomer || vehicle.customer || '',
      status: vehicle.status || 'Ready',
      missing,
      tone: missing.includes('VIN') || missing.includes('tag/plate') ? 'bad' : 'warn'
    };
  });
}
function dailyCloseoutSignoffGap(data = {}, todayKeyValue = localDateKey()) {
  const payload = dailyCloseoutNotificationPayload(data, todayKeyValue);
  const summary = payload.summary || {};
  const activityCount = Number(summary.pending || 0) +
    Number(summary.paidTransactions || 0) +
    Number(summary.transactions || 0) +
    Number(summary.openPaymentRequests || 0) +
    Number(summary.openCardSetupRequests || 0) +
    Number(summary.pendingStarApprovals || 0) +
    Number(summary.verificationItems || 0) +
    Number(summary.vehicleAssignmentConflicts || 0) +
    Number(summary.staleAutopaySchedules || 0) +
    Number(summary.auditEvents || 0);
  const moneyActivity = Number(summary.expected || 0) + Number(summary.collected || 0) + Number(summary.openPaymentRequestAmount || 0);
  const needsSignoff = (activityCount > 0 || moneyActivity > 0) && !summary.signedOff;
  return {
    dateKey: todayKeyValue,
    needsSignoff,
    signedOff: !!summary.signedOff,
    signedAt: summary.signedAt || '',
    signedBy: summary.signedBy || '',
    expected: Number(summary.expected || 0),
    collected: Number(summary.collected || 0),
    stillOpenAmount: Number(summary.stillOpenAmount || 0),
    pending: Number(summary.pending || 0),
    failedTwice: Number(summary.failedTwice || 0),
    paymentNotFound: Number(summary.paymentNotFound || 0),
    openPaymentRequests: Number(summary.openPaymentRequests || 0),
    openCardSetupRequests: Number(summary.openCardSetupRequests || 0),
    pendingStarApprovals: Number(summary.pendingStarApprovals || 0),
    verificationItems: Number(summary.verificationItems || 0),
    vehicleAssignmentConflicts: Number(summary.vehicleAssignmentConflicts || 0),
    staleAutopaySchedules: Number(summary.staleAutopaySchedules || 0),
    auditEvents: Number(summary.auditEvents || 0),
    activityCount,
    tone: needsSignoff ? (Number(summary.failedTwice || 0) || Number(summary.paymentNotFound || 0) || Number(summary.vehicleAssignmentConflicts || 0) ? 'bad' : 'warn') : 'good'
  };
}
function serviceIdentityGapRows(data = {}) {
  return (Array.isArray(data.maintenance) ? data.maintenance : []).filter(job => {
    const status = String(job.status || '').toLowerCase();
    return !/(complete|fixed|closed|done|cancel|removed)/.test(status);
  }).map(job => {
    const customer = job.customer || job.name || '';
    const vehicle = reportVehicleFor(data, customer, job.vehicleId);
    const vehicleText = vehicle.id ? vehicleNameFromParts(vehicle) : String(job.vehicle || '').trim();
    const vin = vehicle.vin || job.vin || '';
    const tag = vehicle.plate || vehicle.stock || job.plate || job.licensePlate || job.tag || '';
    const tracker = trackerName(vehicle) || trackerName(job);
    const typeText = String([job.type, job.issue, job.notes].filter(Boolean).join(' '));
    const cycleJob = /inspection|oil|monthly|service/i.test(typeText);
    const missing = [];
    if (!vehicle.id && !(vehicleText || vin || tag)) missing.push('vehicle link');
    if (!vin) missing.push('VIN');
    if (!tag) missing.push('tag/plate');
    if (!tracker) missing.push('tracker');
    if (!customer && !/prep|lot|inventory/i.test(typeText)) missing.push('customer');
    if (cycleJob && !recordDateKey(job.due || job.nextDue || '')) missing.push('due date');
    return {
      id: job.id || '',
      customer: customer || 'Unassigned',
      vehicle: vehicleText || 'Unlinked service vehicle',
      type: job.type || job.issue || 'Service',
      due: recordDateKey(job.due || job.nextDue || ''),
      status: job.status || 'Open',
      missing,
      tone: missing.some(item => /vehicle link|VIN|tag\/plate|customer/.test(item)) ? 'bad' : (missing.length ? 'warn' : 'good')
    };
  }).filter(row => row.missing.length);
}
function claimEvidenceGapRows(data = {}) {
  return (Array.isArray(data.claims) ? data.claims : []).filter(claim => {
    const status = String(claim.status || '').toLowerCase();
    return !/(paid|closed|complete|resolved|cancel|removed)/.test(status);
  }).map(claim => {
    const customer = claim.customer || claim.name || '';
    const vehicle = reportVehicleFor(data, customer, claim.vehicleId);
    const vehicleText = vehicle.id ? vehicleNameFromParts(vehicle) : String(claim.vehicle || '').trim();
    const vin = vehicle.vin || claim.vin || '';
    const tag = vehicle.plate || vehicle.stock || claim.plate || claim.licensePlate || claim.reference || '';
    const typeText = String([claim.type, claim.source, claim.provider, claim.notes].filter(Boolean).join(' '));
    const proof = String(claim.proofUrl || claim.evidence || claim.documentUrl || claim.url || claim.receiptUrl || '').trim();
    const recovery = /toll|violation|ticket|damage|claim|dispute|chargeback|reimbursement|ezpass/i.test(typeText);
    const missing = [];
    if (weakClaimCustomer(customer) || String(claim.customerMatchStatus || '') === 'Needs payment/customer match') missing.push('customer match');
    if (!vehicle.id && !(vehicleText || vin || tag)) missing.push('vehicle link');
    if (!vin && !tag) missing.push('VIN/tag');
    if (recovery && !Number(claim.amount || 0)) missing.push('amount');
    if (recovery && !proof && !String(claim.externalId || claim.caseId || claim.disputeId || '').trim()) missing.push('proof/reference');
    if (/dispute|chargeback|claim/i.test(typeText) && !recordDateKey(claim.deadline || claim.nextFollowUp || claim.due || '')) missing.push('deadline/follow-up');
    return {
      id: claim.id || '',
      customer: customer || 'Unmatched',
      vehicle: vehicleText || 'Unlinked claim vehicle',
      type: claim.type || claim.source || 'Claim',
      amount: Number(claim.amount || 0),
      status: claim.status || 'Open',
      missing,
      tone: missing.some(item => /customer match|vehicle link|VIN\/tag|proof\/reference/.test(item)) ? 'bad' : (missing.length ? 'warn' : 'good')
    };
  }).filter(row => row.missing.length);
}
function companyScopeGapRows(data = {}) {
  const organizations = Array.isArray(data.organizations) ? data.organizations : [];
  const activeOrgIds = new Set(organizations.filter(org => !/removed|disabled|closed/i.test(String(org.status || 'Active'))).map(org => String(org.id || '').trim()).filter(Boolean));
  if (activeOrgIds.size <= 1) return [];
  const collections = [
    ['vehicles', 'Fleet'],
    ['customers', 'Customers'],
    ['contracts', 'Customer files'],
    ['recurringPayments', 'Autopay'],
    ['payments', 'Payments'],
    ['paymentRequests', 'Payment links'],
    ['cardSetupRequests', 'Card setup'],
    ['maintenance', 'Service'],
    ['claims', 'Claims'],
    ['messages', 'Messages'],
    ['tasks', 'Tasks'],
    ['documents', 'Documents'],
    ['applications', 'Applications'],
    ['staffAccounts', 'Staff'],
    ['customerAccounts', 'Customer portal']
  ];
  const rows = [];
  collections.forEach(([key, label]) => {
    (Array.isArray(data[key]) ? data[key] : []).forEach(row => {
      const status = String(row && (row.status || row.stage) || '').toLowerCase();
      if (/removed|deleted|archived/.test(status)) return;
      const explicit = String(row && (row.organizationId || row.orgId || row.companyId) || '').trim();
      if (!explicit || !activeOrgIds.has(explicit)) {
        rows.push({
          collection: label,
          id: row && row.id || '',
          customer: row && (row.customer || row.name || row.username || row.email || '') || '',
          vehicle: row && (row.vehicle || [row.year, row.make, row.model].filter(Boolean).join(' ')) || '',
          missing: explicit ? ['saved company not found'] : ['company scope'],
          tone: explicit ? 'bad' : 'warn'
        });
      }
    });
  });
  return rows.slice(0, 200);
}
