    const response = await fetch(CLOVER_CHARGE_BASE + pathname, {
      ...options,
      headers: {
        ...(options.headers || {}),
        ...cloverEcommerceAuthHeaders(mode)
      }
    });
    const text = await response.text();
    let body = {};
    try { body = text ? JSON.parse(text) : {}; } catch { body = { raw: text }; }
